import{_ as e,o as s,c as t,a3 as n}from"./chunks/framework.DACwFHq9.js";const k=JSON.parse('{"title":"Kafka 高性能原理","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/performance.md","filePath":"middleware/kafka/performance.md","lastUpdated":1783394230000}'),i={name:"middleware/kafka/performance.md"};function r(l,a,p,d,o,h){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="kafka-gao-xing-neng-yuan-li" tabindex="-1">Kafka 高性能原理 <a class="header-anchor" href="#kafka-gao-xing-neng-yuan-li" aria-label="Permalink to &quot;Kafka 高性能原理&quot;">​</a></h1><p>Kafka 的高吞吐不是单点技巧，而是一组设计叠加出来的结果：顺序写、批量处理、Page Cache、零拷贝、分区并行、压缩和 Pull 模型。</p><h2 id="zong-ti-lian-lu" tabindex="-1">总体链路 <a class="header-anchor" href="#zong-ti-lian-lu" aria-label="Permalink to &quot;总体链路&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer</span></span>
<span class="line"><span>  │  批量、压缩、异步发送</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Broker</span></span>
<span class="line"><span>  │  顺序追加、Page Cache、零拷贝</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Consumer</span></span>
<span class="line"><span>     批量拉取、按 Partition 并行处理</span></span></code></pre></div><p>性能优化要顺着这条链路看：Producer 是否攒得起批次，Broker 是否顺序写和顺序读，Consumer 是否及时拉取并处理。</p><h2 id="shun-xu-xie" tabindex="-1">顺序写 <a class="header-anchor" href="#shun-xu-xie" aria-label="Permalink to &quot;顺序写&quot;">​</a></h2><p>磁盘慢通常慢在随机寻址，而不是顺序吞吐。Kafka 把 Partition 设计成追加日志：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>00000000000000000000.log</span></span>
<span class="line"><span>┌────────┬────────┬────────┬────────┐</span></span>
<span class="line"><span>│ msg 0  │ msg 1  │ msg 2  │ msg 3  │  append only</span></span>
<span class="line"><span>└────────┴────────┴────────┴────────┘</span></span></code></pre></div><p>顺序写带来的好处：</p><ul><li>减少磁盘寻道</li><li>写入模式简单，不需要频繁原地更新</li><li>Segment 只读后便于缓存、复制和删除</li><li>和 Producer 批量发送天然匹配</li></ul><p>Kafka 把“更新消息状态”的复杂度转移到 Offset 和 Consumer Group 元数据中，而不是修改原始消息。</p><h2 id="pi-liang-chu-li" tabindex="-1">批量处理 <a class="header-anchor" href="#pi-liang-chu-li" aria-label="Permalink to &quot;批量处理&quot;">​</a></h2><p>Kafka 的性能单位通常不是单条消息，而是 <strong>Record Batch</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ProducerRecord</span></span>
<span class="line"><span>ProducerRecord      ──► RecordAccumulator ──► Record Batch ──► Broker</span></span>
<span class="line"><span>ProducerRecord</span></span></code></pre></div><p>批量带来的收益：</p><table tabindex="0"><thead><tr><th>位置</th><th>收益</th></tr></thead><tbody><tr><td>Producer</td><td>减少网络请求次数</td></tr><tr><td>Broker</td><td>减少系统调用和索引更新次数</td></tr><tr><td>网络</td><td>提高包利用率</td></tr><tr><td>压缩</td><td>批量越大，压缩率通常越好</td></tr><tr><td>Consumer</td><td>单次 Fetch 返回更多数据，减少往返</td></tr></tbody></table><p>关键配置：</p><table tabindex="0"><thead><tr><th>配置</th><th>作用</th><th>取舍</th></tr></thead><tbody><tr><td><code>batch.size</code></td><td>单个 Partition 批次大小</td><td>大批次提升吞吐，但占用更多内存</td></tr><tr><td><code>linger.ms</code></td><td>等待更多消息组成批次</td><td>增大可提升吞吐，但增加延迟</td></tr><tr><td><code>buffer.memory</code></td><td>Producer 总缓冲区</td><td>太小会导致发送阻塞</td></tr><tr><td><code>max.request.size</code></td><td>单个请求最大大小</td><td>需要和 Broker 限制配套</td></tr></tbody></table><h2 id="page-cache" tabindex="-1">Page Cache <a class="header-anchor" href="#page-cache" aria-label="Permalink to &quot;Page Cache&quot;">​</a></h2><p>Kafka 不把大量消息放在 JVM 堆里，而是依赖操作系统 Page Cache。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Broker JVM</span></span>
<span class="line"><span>  │  write()</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>OS Page Cache</span></span>
<span class="line"><span>  │  异步刷盘</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Disk</span></span></code></pre></div><p>这种设计减少了两类成本：</p><ul><li>JVM 堆对象少，GC 压力低</li><li>热数据直接从 Page Cache 读，不必进入应用层缓存</li></ul><p>Consumer 追得比较近时，刚写入的数据通常还在 Page Cache 中，读取接近内存速度。这也是 Kafka 适合“实时日志流”的原因之一。</p><h2 id="ling-kao-bei" tabindex="-1">零拷贝 <a class="header-anchor" href="#ling-kao-bei" aria-label="Permalink to &quot;零拷贝&quot;">​</a></h2><p>普通文件发送到网络可能经历多次数据拷贝：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Disk -&gt; Kernel Buffer -&gt; User Buffer -&gt; Socket Buffer -&gt; NIC</span></span></code></pre></div><p>Kafka 可以使用 <code>sendfile</code> 这类零拷贝机制，把文件数据从 Page Cache 直接发送到 Socket：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Disk/Page Cache -&gt; Socket Buffer -&gt; NIC</span></span></code></pre></div><p>减少用户态和内核态之间的数据拷贝后，Broker CPU 消耗下降，网络吞吐更容易打满。</p><h2 id="fen-qu-bing-xing" tabindex="-1">分区并行 <a class="header-anchor" href="#fen-qu-bing-xing" aria-label="Permalink to &quot;分区并行&quot;">​</a></h2><p>Partition 是 Kafka 的并行度单位。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Topic orders</span></span>
<span class="line"><span>├── Partition 0 ── Leader Broker 1 ── Consumer A</span></span>
<span class="line"><span>├── Partition 1 ── Leader Broker 2 ── Consumer B</span></span>
<span class="line"><span>└── Partition 2 ── Leader Broker 3 ── Consumer C</span></span></code></pre></div><p>分区带来的能力：</p><ul><li>多 Broker 分摊写入和读取压力</li><li>Consumer Group 内多个 Consumer 并行消费</li><li>不同 Partition 的 Leader 可分散在不同 Broker</li><li>单个 Topic 可通过增加 Partition 扩展吞吐</li></ul><p>但 Partition 不是越多越好。Partition 过多会增加：</p><ul><li>Broker 文件句柄和内存占用</li><li>Controller 元数据管理压力</li><li>Rebalance 时间</li><li>Leader 选举和副本同步成本</li></ul><h2 id="ya-suo" tabindex="-1">压缩 <a class="header-anchor" href="#ya-suo" aria-label="Permalink to &quot;压缩&quot;">​</a></h2><p>Kafka 支持 Producer 端压缩，Broker 通常直接保存压缩后的 Record Batch。</p><table tabindex="0"><thead><tr><th>算法</th><th>特点</th><th>适用</th></tr></thead><tbody><tr><td><code>lz4</code></td><td>压缩/解压快，延迟低</td><td>通用高吞吐场景</td></tr><tr><td><code>zstd</code></td><td>压缩率高，CPU 成本较高</td><td>网络或磁盘成本敏感</td></tr><tr><td><code>snappy</code></td><td>速度快，压缩率中等</td><td>兼容性场景</td></tr><tr><td><code>gzip</code></td><td>压缩率较高，CPU 成本高</td><td>低频、大批量</td></tr></tbody></table><p>压缩的收益不只是节省磁盘，也能减少网络传输和 Page Cache 占用。代价是 Producer 和 Consumer 需要更多 CPU。</p><h2 id="pull-mo-xing" tabindex="-1">Pull 模型 <a class="header-anchor" href="#pull-mo-xing" aria-label="Permalink to &quot;Pull 模型&quot;">​</a></h2><p>Kafka Consumer 主动拉取消息，而不是 Broker 主动推送。</p><p>Pull 模型的好处：</p><ul><li>Consumer 可以按自身处理能力控制速率</li><li>Broker 不需要维护复杂的每客户端推送状态</li><li>Consumer 可以批量拉取，提升吞吐</li><li>消费失败后可按 Offset 重放</li></ul><p>关键配置：</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>fetch.min.bytes</code></td><td>Broker 至少积累多少字节再返回</td></tr><tr><td><code>fetch.max.wait.ms</code></td><td>最长等待时间</td></tr><tr><td><code>max.partition.fetch.bytes</code></td><td>单个 Partition 单次 Fetch 最大数据量</td></tr><tr><td><code>max.poll.records</code></td><td>单次 poll 返回的最大记录数</td></tr></tbody></table><h2 id="xing-neng-diao-you-fang-xiang" tabindex="-1">性能调优方向 <a class="header-anchor" href="#xing-neng-diao-you-fang-xiang" aria-label="Permalink to &quot;性能调优方向&quot;">​</a></h2><h3 id="gao-tun-tu-producer" tabindex="-1">高吞吐 Producer <a class="header-anchor" href="#gao-tun-tu-producer" aria-label="Permalink to &quot;高吞吐 Producer&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">compression.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=lz4</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">batch.size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=131072</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">linger.ms</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=10</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">buffer.memory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=67108864</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">acks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=all</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">enable.idempotence</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre></div><h3 id="di-yan-chi-producer" tabindex="-1">低延迟 Producer <a class="header-anchor" href="#di-yan-chi-producer" aria-label="Permalink to &quot;低延迟 Producer&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">linger.ms</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">batch.size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=16384</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">compression.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=lz4</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">acks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1</span></span></code></pre></div><p>低延迟配置要谨慎牺牲可靠性。如果业务不能丢消息，<code>acks=all</code> 和副本配置优先级高于延迟。</p><h3 id="gao-tun-tu-consumer" tabindex="-1">高吞吐 Consumer <a class="header-anchor" href="#gao-tun-tu-consumer" aria-label="Permalink to &quot;高吞吐 Consumer&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fetch.min.bytes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1048576</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fetch.max.wait.ms</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=500</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">max.poll.records</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1000</span></span></code></pre></div><p>如果处理逻辑慢，应优先优化业务处理或扩容 Partition / Consumer，而不是盲目增大拉取批次。</p><h2 id="pan-duan-ping-jing" tabindex="-1">判断瓶颈 <a class="header-anchor" href="#pan-duan-ping-jing" aria-label="Permalink to &quot;判断瓶颈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能瓶颈</th></tr></thead><tbody><tr><td>Producer <code>bufferpool-wait-time</code> 高</td><td>Broker 写入慢或网络慢</td></tr><tr><td>Request 延迟高</td><td>Broker 磁盘、网络、ISR 同步慢</td></tr><tr><td>Consumer Lag 持续增长</td><td>Consumer 处理慢或 Partition 并行度不足</td></tr><tr><td>Broker CPU 高</td><td>压缩、解压、网络线程不足</td></tr><tr><td>磁盘 Util 高</td><td>写入量过大、保留策略不合理、刷盘过频</td></tr></tbody></table><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#design" target="_blank" rel="noreferrer">Kafka Design</a></li><li><a href="https://kafka.apache.org/documentation/#producerconfigs" target="_blank" rel="noreferrer">Kafka Producer Configs</a></li><li><a href="https://kafka.apache.org/documentation/#consumerconfigs" target="_blank" rel="noreferrer">Kafka Consumer Configs</a></li></ul>`,60)])])}const u=e(i,[["render",r]]);export{k as __pageData,u as default};
